REQUIRED = {'business_rule', 'case_id', 'extra_policy', 'json_schema', 'valid_fixture'}
REJECT = 'REJECT_SCHEMA'

def assess(record: dict) -> str:
    absent = sorted(REQUIRED - record.keys())
    if absent:
        return "MISSING:" + ",".join(absent)
    contract_ok = not (record["extra_policy"] == "allow" and not record["business_rule"])
    return "PASS" if contract_ok else REJECT

valid_fx = {"case_id": 'CASO-CUS-042-1A', **{'extra_policy': 'forbid', 'json_schema': True, 'valid_fixture': True, 'business_rule': True}}
